1	package graphql_test
2	
3	import (
4		"bytes"
5		"encoding/json"
6		"net/http"
7		"net/http/httptest"
8		"os"
9		"path/filepath"
10		"strings"
11		"testing"
12		"time"
13	
14		"github.com/99designs/gqlgen/graphql/handler"
15		"github.com/99designs/gqlgen/graphql/handler/transport"
16	
17		"github.com/DocumentDrivenDX/ddx/internal/bead"
18		ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
19	)
20	
21	// setupOperatorPromptHarness builds a gqlgen handler wired with a real bead
22	// store, a fixed CSRF token, and a process-local idempotency cache. The
23	// handler injects the originating *http.Request into the resolver context
24	// (mirroring the production server's handleGraphQLQuery wrapping) so the
25	// resolver can validate CSRF headers and capture identity.
26	func setupOperatorPromptHarness(t *testing.T) (http.Handler, *bead.Store, string) {
27		t.Helper()
28	
29		workDir, err := os.MkdirTemp("", "operator-prompt-")
30		if err != nil {
31			t.Fatal(err)
32		}
33		t.Cleanup(func() { _ = os.RemoveAll(workDir) })
34	
35		ddxDir := filepath.Join(workDir, ".ddx")
36		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
37			t.Fatal(err)
38		}
39		cfg := "version: \"1.0\"\nbead:\n  id_prefix: \"op\"\n"
40		if err := os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(cfg), 0o644); err != nil {
41			t.Fatal(err)
42		}
43		store := bead.NewStore(ddxDir)
44		if err := store.Init(); err != nil {
45			t.Fatal(err)
46		}
47	
48		const token = "test-csrf-token-deadbeef"
49		cache := ddxgraphql.NewMemoryIdempotencyCache()
50		csrf := ddxgraphql.NewStaticCSRFTokenStoreWithToken(token)
51	
52		gql := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
53			Resolvers: &ddxgraphql.Resolver{
54				WorkingDir:                workDir,
55				CSRFTokens:                csrf,
56				OperatorPromptIdempotency: cache,
57			},
58			Directives: ddxgraphql.DirectiveRoot{},
59		}))
60		gql.AddTransport(transport.POST{})
61		gql.AddTransport(transport.GET{})
62	
63		wrapped := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
64			r = r.WithContext(ddxgraphql.WithHTTPRequest(r.Context(), r))
65			gql.ServeHTTP(w, r)
66		})
67		return wrapped, store, token
68	}
69	
70	const operatorPromptMutation = `mutation Submit($input: OperatorPromptSubmitInput!) {
71		operatorPromptSubmit(input: $input) {
72			bead { id title status issueType description acceptance labels priority }
73			deduplicated
74		}
75	}`
76	
77	// gqlSubmitRaw issues a raw POST and returns the parsed top-level response so
78	// callers can assert on either data or errors.
79	func gqlSubmitRaw(t *testing.T, h http.Handler, csrfHeader, prompt, idemKey string, tier *int) (int, map[string]json.RawMessage) {
80		t.Helper()
81		input := map[string]any{
82			"prompt":         prompt,
83			"idempotencyKey": idemKey,
84		}
85		if tier != nil {
86			input["tier"] = *tier
87		}
88		body, _ := json.Marshal(map[string]any{
89			"query":     operatorPromptMutation,
90			"variables": map[string]any{"input": input},
91		})
92		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(body))
93		req.Header.Set("Content-Type", "application/json")
94		if csrfHeader != "" {
95			req.Header.Set(ddxgraphql.CSRFHeaderName, csrfHeader)
96		}
97		w := httptest.NewRecorder()
98		h.ServeHTTP(w, req)
99		var resp map[string]json.RawMessage
100		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
101			t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
102		}
103		return w.Code, resp
104	}
105	
106	// AC #1: operatorPromptSubmit mutation in schema — covered by every test in
107	// this file (the mutation parses, executes, and returns typed fields).
108	
109	// AC #5: Default = proposed; AC #4 (audit identity captured).
110	func TestOperatorPromptSubmit_HappyPath(t *testing.T) {
111		h, store, token := setupOperatorPromptHarness(t)
112	
113		_, resp := gqlSubmitRaw(t, h, token, "Investigate flaky test in workers_test.go\nFollow up.", "key-1", nil)
114		if errs, ok := resp["errors"]; ok {
115			t.Fatalf("unexpected errors: %s", errs)
116		}
117	
118		var data struct {
119			OperatorPromptSubmit struct {
120				Bead struct {
121					ID          string   `json:"id"`
122					Title       string   `json:"title"`
123					Status      string   `json:"status"`
124					IssueType   string   `json:"issueType"`
125					Description string   `json:"description"`
126					Labels      []string `json:"labels"`
127					Priority    int      `json:"priority"`
128					Acceptance  string   `json:"acceptance"`
129				} `json:"bead"`
130				Deduplicated bool `json:"deduplicated"`
131			} `json:"operatorPromptSubmit"`
132		}
133		if err := json.Unmarshal(resp["data"], &data); err != nil {
134			t.Fatalf("parse: %v", err)
135		}
136		got := data.OperatorPromptSubmit
137		if got.Bead.ID == "" {
138			t.Fatal("expected a bead ID")
139		}
140		if got.Bead.Status != bead.StatusProposed {
141			t.Errorf("status: want %q (default operator-prompt status), got %q", bead.StatusProposed, got.Bead.Status)
142		}
143		if got.Bead.IssueType != bead.IssueTypeOperatorPrompt {
144			t.Errorf("issueType: want %q, got %q", bead.IssueTypeOperatorPrompt, got.Bead.IssueType)
145		}
146		if got.Bead.Title != "Investigate flaky test in workers_test.go" {
147			t.Errorf("title: want first line of prompt, got %q", got.Bead.Title)
148		}
149		if got.Deduplicated {
150			t.Error("first submission must not be marked deduplicated")
151		}
152	
153		// AC #4: audit event records identity.
154		events, err := store.EventsByKind(got.Bead.ID, ddxgraphql.OperatorPromptEventKind)
155		if err != nil {
156			t.Fatalf("read events: %v", err)
157		}
158		if len(events) != 1 {
159			t.Fatalf("want 1 audit event of kind %q, got %d", ddxgraphql.OperatorPromptEventKind, len(events))
160		}
161		ev := events[0]
162		if ev.Actor == "" {
163			t.Error("audit event must record an actor identity")
164		}
165		if !containsAll(ev.Body, "identity=", "idempotency_key=key-1") {
166			t.Errorf("audit body missing identity/key fields: %q", ev.Body)
167		}
168	}
169	
170	// AC #2: CSRF required (returns 403 without).
171	func TestOperatorPromptSubmit_CSRF(t *testing.T) {
172		h, _, token := setupOperatorPromptHarness(t)
173	
174		t.Run("missing header rejected", func(t *testing.T) {
175			_, resp := gqlSubmitRaw(t, h, "", "do a thing", "csrf-missing", nil)
176			assertCSRFError(t, resp)
177		})
178		t.Run("wrong token rejected", func(t *testing.T) {
179			_, resp := gqlSubmitRaw(t, h, "not-the-token", "do a thing", "csrf-wrong", nil)
180			assertCSRFError(t, resp)
181		})
182		t.Run("valid token accepted", func(t *testing.T) {
183			_, resp := gqlSubmitRaw(t, h, token, "do a thing", "csrf-ok", nil)
184			if errs, ok := resp["errors"]; ok {
185				t.Fatalf("unexpected errors with valid CSRF: %s", errs)
186			}
187		})
188	}
189	
190	func assertCSRFError(t *testing.T, resp map[string]json.RawMessage) {
191		t.Helper()
192		errs, ok := resp["errors"]
193		if !ok {
194			t.Fatal("expected GraphQL errors when CSRF token absent or invalid")
195		}
196		var parsed []struct {
197			Message string `json:"message"`
198		}
199		if err := json.Unmarshal(errs, &parsed); err != nil {
200			t.Fatalf("parse errors: %v", err)
201		}
202		if len(parsed) == 0 {
203			t.Fatal("expected at least one error")
204		}
205		msg := parsed[0].Message
206		// AC #2 wording: "returns 403 without". The HTTP transport for
207		// gqlgen's POST handler returns 200 with a structured error; the
208		// resolver's error message must surface the 403 status so a
209		// browser-side gateway can translate (and so audit logs differentiate
210		// CSRF rejections from other failures).
211		if !contains(msg, "CSRF") || !contains(msg, "403") {
212			t.Errorf("error must mention CSRF and 403, got %q", msg)
213		}
214	}
215	
216	// AC #3: idempotency key dedupes within 24h window.
217	func TestOperatorPromptSubmit_Idempotency(t *testing.T) {
218		h, store, token := setupOperatorPromptHarness(t)
219	
220		_, first := gqlSubmitRaw(t, h, token, "first prompt", "idem-key-A", nil)
221		_, second := gqlSubmitRaw(t, h, token, "different prompt body!", "idem-key-A", nil)
222		_, third := gqlSubmitRaw(t, h, token, "third prompt", "idem-key-B", nil)
223	
224		firstID := mustBeadID(t, first)
225		secondID := mustBeadID(t, second)
226		thirdID := mustBeadID(t, third)
227	
228		if firstID != secondID {
229			t.Errorf("idempotency: same key must return same bead ID, got %q vs %q", firstID, secondID)
230		}
231		if firstID == thirdID {
232			t.Errorf("different keys must produce different beads, got %q twice", firstID)
233		}
234		if !mustDeduplicated(t, second) {
235			t.Error("second submission must be marked deduplicated=true")
236		}
237		if mustDeduplicated(t, first) || mustDeduplicated(t, third) {
238			t.Error("first/third submissions must be marked deduplicated=false")
239		}
240	
241		// Audit: only one audit event on the deduped bead (we did not append
242		// a second event for the duplicate).
243		events, err := store.EventsByKind(firstID, ddxgraphql.OperatorPromptEventKind)
244		if err != nil {
245			t.Fatal(err)
246		}
247		if len(events) != 1 {
248			t.Errorf("dedup must not append a second audit event, got %d", len(events))
249		}
250	}
251	
252	// MemoryIdempotencyCache TTL eviction: entries expire after the 24h window.
253	// This locks in the "within 24h" half of AC #3 so a future change to the TTL
254	// does not silently break dedup semantics.
255	func TestMemoryIdempotencyCache_TTLEviction(t *testing.T) {
256		cache := ddxgraphql.NewMemoryIdempotencyCache()
257		now := time.Now()
258		clock := now
259		ddxgraphql.SetMemoryIdempotencyCacheClockForTest(cache, func() time.Time { return clock })
260	
261		cache.Store("k", "bead-1")
262		if id, ok := cache.Lookup("k"); !ok || id != "bead-1" {
263			t.Fatalf("immediate lookup failed: got %q ok=%v", id, ok)
264		}
265		clock = now.Add(23 * time.Hour)
266		if _, ok := cache.Lookup("k"); !ok {
267			t.Error("entry must still be present at 23h")
268		}
269		clock = now.Add(25 * time.Hour)
270		if _, ok := cache.Lookup("k"); ok {
271			t.Error("entry must be evicted past 24h TTL")
272		}
273	}
274	
275	// ─── helpers ───
276	
277	func mustBeadID(t *testing.T, resp map[string]json.RawMessage) string {
278		t.Helper()
279		if errs, ok := resp["errors"]; ok {
280			t.Fatalf("unexpected errors: %s", errs)
281		}
282		var data struct {
283			OperatorPromptSubmit struct {
284				Bead struct {
285					ID string `json:"id"`
286				} `json:"bead"`
287			} `json:"operatorPromptSubmit"`
288		}
289		if err := json.Unmarshal(resp["data"], &data); err != nil {
290			t.Fatalf("parse: %v", err)
291		}
292		if data.OperatorPromptSubmit.Bead.ID == "" {
293			t.Fatal("missing bead ID in response")
294		}
295		return data.OperatorPromptSubmit.Bead.ID
